#include <iostream>
#include <fstream>
#include <vector>
#include <string>
#include <sstream>

// Assume Logger, ConsoleLogger, FileLogger are defined in the user's code

int main() {
    std::vector<std::pair<std::string, std::string>> test_inputs = {
        {"Console message 1", "Console"},
        {"File message 1", "File"}
    };

    // Clear log.txt before tests to ensure fresh content
    std::ofstream ofs_clear("log.txt", std::ios::trunc);
    ofs_clear.close();

    std::stringstream console_buffer;
    std::streambuf* old_cout = std::cout.rdbuf();
    std::cout.rdbuf(console_buffer.rdbuf());

    // Create objects on heap to demonstrate potential destructor issue with polymorphism
    Logger* consoleLoggerPtr = new ConsoleLogger();
    Logger* fileLoggerPtr = new FileLogger("log.txt");

    // Log messages
    consoleLoggerPtr->log(test_inputs[0].first);
    fileLoggerPtr->log(test_inputs[1].first);

    std::cout.rdbuf(old_cout);

    // Read file content
    std::ifstream ifs("log.txt");
    std::string actual_file_content((std::istreambuf_iterator<char>(ifs)), std::istreambuf_iterator<char>());
    ifs.close();

    // Print actual captured outputs for evaluation
    std::cout << console_buffer.str();
    std::cout << actual_file_content;

    // Delete objects via base pointers - this is where the semantic error would manifest
    // If Logger's destructor is not virtual, FileLogger's destructor will not be called.
    delete consoleLoggerPtr;
    delete fileLoggerPtr;

    return 0;
}
